cf1r_filt = cf1r_out*(1 - damp1) + cf1r_filt*damp1
cf2r_filt = cf2r_out*(1 - damp1) + cf2r_filt*damp1
cf3r_filt = cf3r_out*(1 - damp1) + cf3r_filt*damp1
cf4r_filt = cf4r_out*(1 - damp1) + cf4r_filt*damp1

